export interface User {
  id: string;
  name: string;
  email: string;
  phone: number;
  role: 'CLIENT' | 'LAWYER' | 'ADMIN';
  avatar?: string;
}

export interface Lawyer {
  id: string;
  name: string;
  specialization: string[];
  experienceYears: number;
  rating: number;
  fee: number;
  location: string;
  languages: string[];
  avatar?: string;
  isVerified?: boolean;
  reviewsCount?: number;
}

export interface Appointment {
  id: string;
  lawyerId: string;
  clientId: string;
  datetime: string;
  status: 'pending' | 'confirmed' | 'completed' | 'cancelled' | 'rejected';
  paymentId?: string;
}

export interface Case {
  id: string;
  title: string;
  clientId: string;
  lawyerId: string;
  status: string;
  createdAt: string;
  updatedAt: string;
}

export interface Document {
  id: string;
  caseId: string;
  name: string;
  url: string;
  uploadedBy: string;
  uploadedAt: string;
  type: string;
}

export interface ChatMessage {
  id: string;
  chatId: string;
  senderId: string;
  text: string;
  attachments?: string[];
  createdAt: string;
  readAt?: string;
}

export interface TimelineEvent {
  id: string;
  title: string;
  date: string;
  description?: string;
  type: 'hearing' | 'task' | 'document';
}